/**
 * SHALE YEAH Agent OS — Result Cache
 *
 * TTL-based in-memory cache for tool responses, keyed by idempotency keys
 * generated by the executor. Query tools are cacheable; command tools are not.
 *
 * Issue #113: deduplicate repeat requests using the idempotency keys already
 * generated by Executor.generateIdempotencyKey().
 */

import type { ToolResponse } from "./types.js";

export interface ResultCacheConfig {
	/** Time-to-live in milliseconds for each cache entry. */
	ttlMs: number;
}

export interface CacheMetrics {
	/** Number of cache hits since creation. */
	hits: number;
	/** Number of cache misses since creation. */
	misses: number;
	/** Number of live (non-expired) entries currently in the cache. */
	size: number;
}

interface CacheEntry {
	response: ToolResponse;
	expiresAt: number;
}

/**
 * ResultCache — TTL-based result deduplication for tool responses.
 *
 * Usage:
 *   const cache = new ResultCache({ ttlMs: 300_000 });
 *   cache.set(key, response);           // store (query tools only)
 *   cache.set(key, response, false);    // no-op (command tool)
 *   cache.get(key);                     // ToolResponse | undefined
 *   cache.invalidate(key);              // evict one entry
 *   cache.invalidateAll();              // clear everything
 *   cache.metrics;                      // { hits, misses, size }
 */
export class ResultCache {
	private readonly ttlMs: number;
	private readonly store: Map<string, CacheEntry> = new Map();
	private _hits = 0;
	private _misses = 0;

	constructor(config: ResultCacheConfig) {
		this.ttlMs = config.ttlMs;
	}

	// ==========================================
	// Public API
	// ==========================================

	/**
	 * Retrieve a cached response by key.
	 * Returns undefined on miss or if the entry has expired.
	 */
	get(key: string): ToolResponse | undefined {
		const entry = this.store.get(key);
		if (!entry) {
			this._misses++;
			return undefined;
		}
		if (Date.now() > entry.expiresAt) {
			this.store.delete(key);
			this._misses++;
			return undefined;
		}
		this._hits++;
		return entry.response;
	}

	/**
	 * Store a response under the given key.
	 *
	 * @param cacheable - Set to false for command tools; the call becomes a no-op.
	 *                    Defaults to true (query tools).
	 */
	set(key: string, response: ToolResponse, cacheable = true): void {
		if (!cacheable) return;
		this.store.set(key, {
			response,
			expiresAt: Date.now() + this.ttlMs,
		});
	}

	/**
	 * Remove a specific entry from the cache.
	 * Safe to call for keys that don't exist.
	 */
	invalidate(key: string): void {
		this.store.delete(key);
	}

	/**
	 * Remove all entries from the cache.
	 */
	invalidateAll(): void {
		this.store.clear();
	}

	/**
	 * Current cache metrics: hits, misses, and live entry count.
	 * Size reflects only non-expired entries.
	 */
	get metrics(): CacheMetrics {
		const now = Date.now();
		let liveCount = 0;
		for (const entry of this.store.values()) {
			if (entry.expiresAt > now) liveCount++;
		}
		return {
			hits: this._hits,
			misses: this._misses,
			size: liveCount,
		};
	}
}
